# Interview Packs

Create one folder or file per active interview.

Naming style:

`company-role.md`

Each pack should include:

- role summary;
- likely evaluation areas;
- technical drills;
- behavioral STAR stories;
- mock interview scorecard;
- questions to ask the interviewer.

Use [../docs/06-interview-prep.md](../docs/06-interview-prep.md) as the working guide.

from __future__ import annotations

import json
from typing import Any

import httpx

from app.core.config import get_settings


class LLMProvider:
    def __init__(
        self,
        model_name: str | None = None,
        api_key: str | None = None,
        base_url: str | None = None,
    ) -> None:
        settings = get_settings()
        self.model_name = model_name or settings.model_name
        self.api_key = api_key if api_key is not None else settings.openai_api_key
        self.base_url = (base_url or settings.openai_base_url).rstrip("/")

    @property
    def configured(self) -> bool:
        return bool(self.model_name and self.base_url and self.api_key)

    async def chat_json(self, system: str, user: str, fallback: dict[str, Any]) -> dict[str, Any]:
        if not self.configured:
            return fallback

        payload = {
            "model": self.model_name,
            "messages": [
                {"role": "system", "content": system},
                {"role": "user", "content": user},
            ],
            "response_format": {"type": "json_object"},
            "temperature": 0.2,
        }
        headers = {"Authorization": f"Bearer {self.api_key}", "Content-Type": "application/json"}

        async with httpx.AsyncClient(timeout=90) as client:
            response = await client.post(
                f"{self.base_url}/chat/completions", json=payload, headers=headers
            )
            response.raise_for_status()
            content = response.json()["choices"][0]["message"]["content"]
            return json.loads(content)

    async def chat_text(self, system: str, user: str, fallback: str) -> str:
        if not self.configured:
            return fallback

        payload = {
            "model": self.model_name,
            "messages": [
                {"role": "system", "content": system},
                {"role": "user", "content": user},
            ],
            "temperature": 0.3,
        }
        headers = {"Authorization": f"Bearer {self.api_key}", "Content-Type": "application/json"}

        async with httpx.AsyncClient(timeout=90) as client:
            response = await client.post(
                f"{self.base_url}/chat/completions", json=payload, headers=headers
            )
            response.raise_for_status()
            return response.json()["choices"][0]["message"]["content"]

from functools import lru_cache
import os
from pathlib import Path

from pydantic import BaseModel


class Settings(BaseModel):
    model_name: str = os.getenv("MODEL_NAME", "gpt-4o-mini")
    openai_api_key: str = os.getenv("OPENAI_API_KEY", "")
    openai_base_url: str = os.getenv("OPENAI_BASE_URL", "https://api.openai.com/v1")
    db_path: str = os.getenv("JOBRADAR_DB_PATH", "./jobradar.db")

    @property
    def resolved_db_path(self) -> Path:
        return Path(self.db_path).expanduser().resolve()


@lru_cache
def get_settings() -> Settings:
    return Settings()

from __future__ import annotations

from pathlib import Path


SUPPORTED_FILE_EXTENSIONS = {".md", ".txt", ".pdf", ".docx"}
SUPPORTED_VAULT_EXTENSIONS = {".md", ".txt"}


def read_document(path: Path) -> str:
    suffix = path.suffix.lower()
    if suffix in {".md", ".txt"}:
        return path.read_text(encoding="utf-8", errors="ignore")
    if suffix == ".pdf":
        try:
            from pypdf import PdfReader

            reader = PdfReader(str(path))
            return "\n".join(page.extract_text() or "" for page in reader.pages)
        except Exception as exc:  # pragma: no cover - depends on optional parser quality
            return f"[Unable to parse PDF {path.name}: {exc}]"
    if suffix == ".docx":
        try:
            from docx import Document

            doc = Document(str(path))
            return "\n".join(p.text for p in doc.paragraphs)
        except Exception as exc:  # pragma: no cover
            return f"[Unable to parse DOCX {path.name}: {exc}]"
    raise ValueError(f"Unsupported file type: {suffix}")


def normalize_uploaded_name(filename: str) -> str:
    return Path(filename).name.replace("\x00", "")

from __future__ import annotations

from typing import Any

from app.modules.llm_provider import LLMProvider


def _score_overlap(profile_skills: set[str], role_skills: set[str]) -> int:
    if not role_skills:
        return 50
    return round(100 * len(profile_skills & role_skills) / len(role_skills))


def fallback_gap_analysis(profile: dict[str, Any], role: dict[str, Any]) -> dict[str, Any]:
    profile_skills = {str(skill).lower() for skill in profile.get("skills", [])}
    role_skills = {str(skill).lower() for skill in role.get("required_skills", [])}
    skills_match = _score_overlap(profile_skills, role_skills)
    missing = sorted(role_skills - profile_skills)
    overall = round((skills_match * 0.45) + 25 + 15 + 10)
    return {
        "overall_match_score": min(100, overall),
        "skills_match": skills_match,
        "experience_match": 50,
        "domain_match": 50,
        "leadership_match": 50,
        "missing_skills": missing,
        "evidence_mapping": [
            {
                "requirement": skill,
                "evidence": "No explicit evidence found" if skill in missing else "Profile skill match",
                "confidence": "Low" if skill in missing else "Medium",
            }
            for skill in sorted(role_skills)
        ],
        "quick_wins": ["Add evidence-backed bullets for matching skills.", "Move role keywords into Skills."],
        "skills_to_learn": [
            {"skill": skill, "estimated_effort": "2-5 days", "reason": "Required by target role"}
            for skill in missing[:5]
        ],
        "portfolio_projects": [
            {
                "project": "Small role-aligned proof project",
                "estimated_impact": "Medium",
                "reason": "Creates evidence for missing requirements.",
            }
        ],
    }


async def analyze_gap(profile: dict[str, Any], role: dict[str, Any]) -> dict[str, Any]:
    fallback = fallback_gap_analysis(profile, role)
    prompt = f"""
Compare this professional profile against the target role. Return JSON with:
overall_match_score, skills_match, experience_match, domain_match, leadership_match,
missing_skills, evidence_mapping, quick_wins, skills_to_learn, portfolio_projects.
Scores must be 0-100. Evidence mapping entries need requirement, evidence, confidence.

Profile:
{profile}

Role:
{role}
"""
    return await LLMProvider().chat_json(
        "You are a precise career gap analyst. Be helpful but do not flatter.",
        prompt,
        fallback,
    )

from __future__ import annotations

from typing import Any

from app.modules.llm_provider import LLMProvider


def first_question(mode: str, difficulty: str) -> str:
    return (
        f"Let's begin a {difficulty.lower()} {mode.lower()} interview. "
        "Tell me about a project that best proves you are a strong fit for this role."
    )


async def evaluate_answer(
    mode: str,
    difficulty: str,
    question: str,
    answer: str,
    context: dict[str, Any] | None = None,
) -> dict[str, Any]:
    fallback = {
        "score": 60,
        "technical_depth": 3,
        "clarity": 3,
        "communication": 3,
        "structure": 3,
        "strengths": ["Answer gives a starting point."],
        "weaknesses": ["Add clearer structure, evidence, and measurable impact."],
        "improved_answer": "Use Situation, Task, Action, Result, then connect the result to the target role.",
        "next_question": "What tradeoffs did you make, and how did you evaluate success?",
    }
    prompt = f"""
Evaluate this interview answer.
Mode: {mode}
Difficulty: {difficulty}
Question: {question}
Answer: {answer}
Context: {context or {}}

Return JSON with score, technical_depth, clarity, communication, structure,
strengths, weaknesses, improved_answer, next_question.
"""
    return await LLMProvider().chat_json(
        "You are a direct but supportive interview coach.",
        prompt,
        fallback,
    )

