  });
  const submit = useMutation({ mutationFn: () => api.answerInterview(Number(sessionId), answer) });

  return (
    <>
      <PageHeader title="Interview Prep" description="Practice technical, behavioral, hiring manager, system design, or mixed interviews with scoring and improved answers." />
