              {["Technical", "Behavioral", "Hiring Manager", "System Design", "Mixed"].map((value) => <option key={value}>{value}</option>)}
            </Select>
            <Select value={difficulty} onChange={(event) => setDifficulty(event.target.value)}>
              {["Easy", "Medium", "Hard"].map((value) => <option key={value}>{value}</option>)}
            </Select>
          </div>
          <Button onClick={() => start.mutate()} disabled={start.isPending}>Start Interview</Button>
          <StatusPanel loading={start.isPending} error={start.error} success={start.data ? `Session #${start.data.session_id}` : undefined} />
          {start.data && <div className="rounded-md bg-muted p-4 text-sm">{start.data.question}</div>}
        </CardContent>
      </Card>
      <Card className="mt-4">
        <CardHeader><CardTitle>Answer</CardTitle></CardHeader>
        <CardContent className="space-y-3">
          <Textarea value={answer} onChange={(event) => setAnswer(event.target.value)} placeholder="Type your answer..." />
          <Button onClick={() => submit.mutate()} disabled={!sessionId || !answer || submit.isPending}>Submit Answer</Button>
          <StatusPanel loading={submit.isPending} error={submit.error} success={submit.data ? "Evaluation ready" : undefined} />
          {submit.data && <pre className="rounded-md bg-muted p-4 text-xs">{JSON.stringify(submit.data.evaluation, null, 2)}</pre>}
        </CardContent>
      </Card>
    </>
  );
}

