    question = first_question(payload.mode, payload.difficulty)
    history = [{"role": "assistant", "content": question}]
    timestamp = now_iso()
    with get_db() as conn:
        cur = conn.execute(
            """
            INSERT INTO interview_sessions
            (profile_id, role_analysis_id, mode, difficulty, history_json, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?)
            """,
            (
