        )
    return {"session_id": int(cur.lastrowid), "question": question, "history": history}


@app.post("/api/interview/answer")
async def answer_interview(payload: InterviewAnswerRequest) -> dict:
    with get_db() as conn:
        row = conn.execute(
            "SELECT * FROM interview_sessions WHERE id = ?", (payload.session_id,)
        ).fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="Interview session not found")

    history = decode_json(row["history_json"])
    question = next((item["content"] for item in reversed(history) if item["role"] == "assistant"), "")
    evaluation = await evaluate_answer(row["mode"], row["difficulty"], question, payload.answer)
    history.extend(
        [
            {"role": "user", "content": payload.answer},
            {"role": "assistant", "content": evaluation["next_question"], "evaluation": evaluation},
        ]
    )
    with get_db() as conn:
        conn.execute(
            "UPDATE interview_sessions SET history_json = ?, updated_at = ? WHERE id = ?",
            (encode_json(history), now_iso(), payload.session_id),
        )
    return {"evaluation": evaluation, "history": history}

